                    c if c < '\u{1f}' => can_be_pretty = false, // Invalid control character
                    _ => {}
                }
                out.push(ch);
            } else {
                // the string cannot be represented as pretty,
                // still check if it should be multiline
                if ch == '\n' {
                    ty = Type::NewlineTripple;
                }
