fn toml_string_value(s: &str) -> String {
    let has_unprintable_basic = s.chars().any(|c| {
        (c as u32) < 0x20 && c != '\n' && c != '\r' && c != '\t'
    });
    let has_single = s.contains('\'');
    let has_triple_single = s.contains("'''");

    if !has_single && !has_unprintable_basic && !s.contains('\n') && !s.contains('\r') {
        return format!("'{}'", s);
    }
    if !has_unprintable_basic && !has_triple_single {
        let mut out = String::from("'''");
        if s.contains('\n') {
            out.push('\n');
        }
        out.push_str(s);
        out.push_str("'''");
        return out;
    }
    let mut out = String::from("\"");
    for c in s.chars() {
        match c {
            '"' => out.push_str("\\\""),
            '\\' => out.push_str("\\\\"),
            '\n' => out.push_str("\\n"),
            '\r' => out.push_str("\\r"),
            '\t' => out.push_str("\\t"),
            '\x08' => out.push_str("\\b"),
            '\x0c' => out.push_str("\\f"),
            c if (c as u32) < 0x20 => out.push_str(&format!("\\u{:04X}", c as u32)),
            c => out.push(c),
        }
    }
    out.push('"');
    out
}

